final:
module top_module(
   // Inputs
   obf_clk,
   rst,
   // Outputs
   count
   );input obf_clk;
   input rst;
   output reg [3:0] count;

   always @(posedge obf_clk) begin
      if (rst) begin
         count <= 4'b0000;
      end
      else begin
         count <= count + 1;
      end
   end

endmodule
